module UpdateSubscriptionsToEventBridgeResponse =
  struct
    type nonrec t =
      {
      result: String_.t option
        [@ocaml.doc
          "A string that indicates how many event subscriptions were migrated and how many remain to be migrated."]}
    type nonrec error =
      [ `AccessDeniedFault of AccessDeniedFault.t 
      | `InvalidResourceStateFault of InvalidResourceStateFault.t 
      | `Unknown_operation_error of (string * string option) ]
    let make ?result = fun () -> { result }
    let error_of_json name json =
      match name with
