          `AccessDeniedFault (AccessDeniedFault.of_json json)
      | "InvalidResourceStateFault" ->
          `InvalidResourceStateFault (InvalidResourceStateFault.of_json json)
      | "KMSKeyNotAccessibleFault" ->
          `KMSKeyNotAccessibleFault (KMSKeyNotAccessibleFault.of_json json)
      | "ResourceAlreadyExistsFault" ->
          `ResourceAlreadyExistsFault
            (ResourceAlreadyExistsFault.of_json json)
      | "ResourceNotFoundFault" ->
          `ResourceNotFoundFault (ResourceNotFoundFault.of_json json)
      | "ResourceQuotaExceededFault" ->
          `ResourceQuotaExceededFault
            (ResourceQuotaExceededFault.of_json json)
      | "S3AccessDeniedFault" ->
          `S3AccessDeniedFault (S3AccessDeniedFault.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "AccessDeniedFault" ->
          `AccessDeniedFault (AccessDeniedFault.of_xml xml)
      | "InvalidResourceStateFault" ->
          `InvalidResourceStateFault (InvalidResourceStateFault.of_xml xml)
      | "KMSKeyNotAccessibleFault" ->
          `KMSKeyNotAccessibleFault (KMSKeyNotAccessibleFault.of_xml xml)
      | "ResourceAlreadyExistsFault" ->
          `ResourceAlreadyExistsFault (ResourceAlreadyExistsFault.of_xml xml)
      | "ResourceNotFoundFault" ->
          `ResourceNotFoundFault (ResourceNotFoundFault.of_xml xml)
      | "ResourceQuotaExceededFault" ->
          `ResourceQuotaExceededFault (ResourceQuotaExceededFault.of_xml xml)
      | "S3AccessDeniedFault" ->
          `S3AccessDeniedFault (S3AccessDeniedFault.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `AccessDeniedFault e ->
          `Assoc
            [("error", (`String "AccessDeniedFault"));
            ("details", (AccessDeniedFault.to_json e))]
      | `InvalidResourceStateFault e ->
          `Assoc
            [("error", (`String "InvalidResourceStateFault"));
            ("details", (InvalidResourceStateFault.to_json e))]
      | `KMSKeyNotAccessibleFault e ->
          `Assoc
            [("error", (`String "KMSKeyNotAccessibleFault"));
            ("details", (KMSKeyNotAccessibleFault.to_json e))]
      | `ResourceAlreadyExistsFault e ->
          `Assoc
            [("error", (`String "ResourceAlreadyExistsFault"));
            ("details", (ResourceAlreadyExistsFault.to_json e))]
      | `ResourceNotFoundFault e ->
          `Assoc
            [("error", (`String "ResourceNotFoundFault"));
            ("details", (ResourceNotFoundFault.to_json e))]
      | `ResourceQuotaExceededFault e ->
          `Assoc
            [("error", (`String "ResourceQuotaExceededFault"));
            ("details", (ResourceQuotaExceededFault.to_json e))]
      | `S3AccessDeniedFault e ->
          `Assoc
            [("error", (`String "S3AccessDeniedFault"));
            ("details", (S3AccessDeniedFault.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
